solution: ```class Solution {
public:
    int sumOfTheDigitsOfHarshadNumber(int x) {
        if (x == 0) return -1;
        int n = x;
        int sum = 0;
        while (n) {
            sum += n % 10;
            n /= 10;
        }
        return (x % sum == 0) ? sum : -1;
    }
};
```
